package main

import (
	"fmt"
	"net/http"
	"io/ioutil"
)

func handler(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		fmt.Fprintf(w, "Error reading request body: %s", err)
		return
	}
	defer r.Body.Close()

	// Print the request content
	fmt.Println("Request Content:", string(body))

	// You can also send the content back in the response if needed
	fmt.Fprint(w, "Request content received and printed.")
}

func main() {
	// Set up the server to listen on port 8080
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}
```

